script:
frappe.ui.form.on("Repair Job", {
    asset_type(frm) {
        if (frm.doc.asset_type === "Club Boat") {
            frm.set_value("machinery", null);
        } else if (frm.doc.asset_type === "Machinery") {
            frm.set_value("boat", null);
        }
    }
});

frappe.ui.form.on('Crane Booking', {
    refresh: function(frm) {
        // Restricts the crane_id dropdown list to 'Machinery' assets only
        frm.set_query('crane_id', function() {
            return {
                filters: {
                    'asset_category': 'Machinery'
                }
            };
        });
    }
});

frappe.ui.form.on('Crane Booking', {
    start_time: calculate_duration,
    end_time: calculate_duration
});

function calculate_duration(frm) {
    if (frm.doc.start_time && frm.doc.end_time) {
        let start = frappe.datetime.str_to_obj(frm.doc.start_time);
        let end = frappe.datetime.str_to_obj(frm.doc.end_time);

        let seconds = (end - start) / 1000;
        frm.set_value('duration', seconds);
    }
}
